import urllib.request
with open("common.txt", "r") as f:
    for line in f:
        path = line.strip()
        if path:
            url = f"http://target:8103/{path}"
            try:
                r = urllib.request.urlopen(url)
                print(f"Found {r.getcode()}: {path}")
            except urllib.error.HTTPError as e:
                if e.code != 404:
                    print(f"Found {e.code}: {path}")
            except Exception:
                pass
